import React, { useState } from 'react';

const App = () => {
  const [darkMode, setDarkMode] = useState(false);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');

  const handleSubmit = (e) => {
    e.preventDefault();
    console.log(username, password);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center\">
      <div className="w-full max-w-md bg-white rounded-md shadow-md p-8\">
        <h2 className="text-lg font-bold mb-4'>Admin Dashboard</h2>
        <form onSubmit={handleSubmit} className="'>
          <div className="mb-4'>
            <label className="block font-bold mb-2'>Username:</label>
            <input type="text" value={username} onChange={(e) => setUsername(e.target.value)}'>
          </div>
          <div className="mb-4'>
            <label className="block font-bold mb-2'>Password:</label>
            <input type="password" value={password} onChange={(e) => setPassword(e.target.value)}'>
          </div>
          <div className="mb-4'>
            <button type="submit" className="bg-[#C06C88] hover:bg-[#C06C88] text-white font-bold py-2 px-4 rounded'>Login</button>
          </div>
        </form>
        <button onClick={() => setDarkMode(!darkMode)} className="bg-[#C06C88] hover:bg-[#C06C88] text-white font-bold py-2 px-4 rounded ml-4'>Toggle Dark Mode</button>
      </div>
    </div>
  );
};

export default App;
